// src/components/admin/AdminCalendar.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function AdminCalendar() {
  const [reservations, setReservations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedReservation, setSelectedReservation] = useState(null);

  const [currentMonth, setCurrentMonth] = useState(new Date().getMonth());
  const [currentYear, setCurrentYear] = useState(new Date().getFullYear());

  useEffect(() => {
    fetchReservations();
  }, []);

  async function fetchReservations() {
    setLoading(true);
    setError(null);
    try {
      const res = await axios.get(`${API_BASE}/api/reservations/`);
      setReservations(Array.isArray(res.data) ? res.data : res.data.results || []);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch reservations");
    } finally {
      setLoading(false);
    }
  }

  // Get days in month
  const getDaysInMonth = (year, month) => {
    return new Date(year, month + 1, 0).getDate();
  };

  // Get first day of month (0 = Sunday, 1 = Monday, etc.)
  const getFirstDayOfMonth = (year, month) => {
    return new Date(year, month, 1).getDay();
  };

  // Generate calendar days
  const generateCalendarDays = () => {
    const daysInMonth = getDaysInMonth(currentYear, currentMonth);
    const firstDay = getFirstDayOfMonth(currentYear, currentMonth);
    const days = [];

    // Empty cells for days before the first day of month
    for (let i = 0; i < firstDay; i++) {
      days.push({ day: null, date: null });
    }

    // Days of the month
    for (let day = 1; day <= daysInMonth; day++) {
      const date = `${currentYear}-${String(currentMonth + 1).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
      days.push({ day, date });
    }

    return days;
  };

  // Get reservations for a specific date
  const getReservationsForDate = (dateStr) => {
    return reservations.filter((r) => {
      const checkIn = r.check_in;
      const checkOut = r.check_out;
      return checkIn <= dateStr && checkOut >= dateStr;
    });
  };

  // Navigation
  const prevMonth = () => {
    if (currentMonth === 0) {
      setCurrentMonth(11);
      setCurrentYear(currentYear - 1);
    } else {
      setCurrentMonth(currentMonth - 1);
    }
  };

  const nextMonth = () => {
    if (currentMonth === 11) {
      setCurrentMonth(0);
      setCurrentYear(currentYear + 1);
    } else {
      setCurrentMonth(currentMonth + 1);
    }
  };

  const goToToday = () => {
    const today = new Date();
    setCurrentMonth(today.getMonth());
    setCurrentYear(today.getFullYear());
  };

  const monthNames = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December"
  ];

  const weekDays = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

  // Stats
  const todayStr = new Date().toISOString().slice(0, 10);
  const todayReservations = getReservationsForDate(todayStr);
  const confirmedCount = reservations.filter((r) => r.status === "Confirmed").length;
  const pendingCount = reservations.filter((r) => r.status === "Pending").length;

  const calendarDays = generateCalendarDays();

  return (
    <div>
      <style>{`
        :root {
          --bg-dark: #181818;
          --bg-sidebar: #202020;
          --text-light: #f1f1f1;
          --text-muted: #aaa;
          --accent: #c89d5c;
          --card-bg: #2a2a2a;
        }
        *{box-sizing:border-box;font-family:"Segoe UI",sans-serif}
        .page{display:flex;min-height:100vh;background:var(--bg-dark);color:var(--text-light)}
        .sidebar-container{width:220px;min-height:100vh;background:var(--bg-sidebar);padding:20px;display:flex;flex-direction:column;position:fixed;top:0;left:0;height:100vh}
        .sidebar-title{color:var(--accent);font-size:20px;margin-bottom:24px;font-weight:600}
        .sidebar-nav{display:flex;flex-direction:column;flex:1}
        .sidebar-link{color:var(--muted);text-decoration:none;padding:10px 12px;border-radius:6px;margin-bottom:4px;transition:all 0.2s ease;display:block}
        .sidebar-link:hover{color:var(--accent);background:rgba(200,157,92,0.1)}
        .sidebar-link.active{background:rgba(200,157,92,0.15);color:var(--accent)}
        .sidebar-logout{margin-top:auto;padding-top:20px;border-top:1px solid #333}
        .main-content{flex:1;margin-left:220px;padding:28px;min-height:100vh}
        h1{color:var(--accent);margin-bottom:16px}
        
        /* Stats Cards */
        .stats-row{display:flex;gap:16px;margin-bottom:24px;flex-wrap:wrap}
        .stat-card{background:var(--card-bg);padding:20px;border-radius:12px;flex:1;min-width:180px}
        .stat-card h3{color:var(--text-muted);margin:0 0 8px;font-size:13px;text-transform:uppercase;letter-spacing:0.5px}
        .stat-card p{color:var(--accent);font-size:28px;font-weight:700;margin:0}
        .stat-card .stat-sub{font-size:12px;color:var(--text-muted);margin-top:4px}
        
        /* Calendar Header */
        .calendar-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:20px}
        .calendar-nav{display:flex;align-items:center;gap:12px}
        .calendar-nav button{background:transparent;border:1px solid #333;color:#fff;padding:8px 16px;border-radius:6px;cursor:pointer;transition:all 0.2s}
        .calendar-nav button:hover{border-color:var(--accent);color:var(--accent)}
        .calendar-title{font-size:24px;font-weight:600;color:var(--accent)}
        .btn-today{background:var(--accent) !important;color:#111 !important;border:none !important;font-weight:600}
        .btn-today:hover{opacity:0.9}
        
        /* Calendar Grid */
        .calendar-container{background:var(--card-bg);border-radius:12px;overflow:hidden}
        .calendar-weekdays{display:grid;grid-template-columns:repeat(7,1fr);background:#252525}
        .calendar-weekdays th{padding:14px;text-align:center;color:var(--accent);font-weight:600;font-size:13px;text-transform:uppercase}
        .calendar-grid{display:grid;grid-template-columns:repeat(7,1fr)}
        .calendar-day{padding:8px;min-height:100px;border:1px solid #333;border-top:none;border-left:none;text-align:left;vertical-align:top;transition:background 0.2s}
        .calendar-day:nth-child(7n){border-right:none}
        .calendar-day:hover{background:#252525}
        .calendar-day.other-month{background:#1a1a1a}
        .calendar-day.other-month .day-number{color:var(--text-muted)}
        .calendar-day.today{background:rgba(200,157,92,0.1)}
        .calendar-day.today .day-number{background:var(--accent);color:#111;border-radius:50%;width:28px;height:28px;display:flex;align-items:center;justify-content:center}
        .day-number{font-size:14px;font-weight:500;margin-bottom:6px}
        .day-events{display:flex;flex-direction:column;gap:2px}
        .event-chip{padding:3px 6px;border-radius:4px;font-size:11px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;cursor:pointer}
        .event-chip.confirmed{background:rgba(76,175,80,0.2);color:#4caf50;border-left:2px solid #4caf50}
        .event-chip.pending{background:rgba(230,195,77,0.2);color:#e6c34d;border-left:2px solid #e6c34d}
        .event-chip.cancelled{background:rgba(229,57,53,0.2);color:#e53935;border-left:2px solid #e53935}
        
        /* Modal */
        .modal-backdrop{position:fixed;inset:0;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:60}
        .modal{background:#1a1a1a;padding:24px;border-radius:12px;max-width:500px;width:94%;color:var(--text-light);box-shadow:0 8px 30px rgba(0,0,0,0.6)}
        .modal h3{margin:0 0 16px;color:var(--accent);font-size:20px}
        .modal-close{float:right;background:transparent;border:none;color:#fff;font-size:24px;cursor:pointer}
        .modal-close:hover{color:var(--accent)}
        .detail-row{display:flex;justify-content:space-between;padding:10px 0;border-bottom:1px solid #333}
        .detail-row:last-child{border-bottom:none}
        .detail-label{color:var(--text-muted)}
        .detail-value{font-weight:500}
        
        .loading{text-align:center;padding:40px;color:var(--text-muted)}
        .error{text-align:center;padding:40px;color:#e53935}
        
        @media (max-width:900px){
          .sidebar-container{display:none}
          .main-content{padding:16px;margin-left:0}
          .calendar-day{min-height:60px;padding:4px}
          .event-chip{display:none}
          .calendar-day.today .day-number{width:24px;height:24px;font-size:12px}
        }
      `}</style>

      <div className="page">
        <aside className="sidebar-container">
          <h2 className="sidebar-title">Admin</h2>
          <nav className="sidebar-nav">
            <a href="/admin" className="sidebar-link">Dashboard</a>
            <a href="/admin/reservations" className="sidebar-link">Reservations</a>
            <a href="/admin/rooms" className="sidebar-link">Rooms</a>
            <a href="/admin/customers" className="sidebar-link">Customers</a>
            <a href="/admin/calendar" className="sidebar-link active">Calendar</a>
            <a href="/admin/guest-activity" className="sidebar-link">Guest Activity</a>
            <a href="/admin/staff" className="sidebar-link">Staff</a>
            <a href="/admin/gallery" className="sidebar-link">Gallery</a>
            <a href="/admin/reviews" className="sidebar-link">Reviews</a>
          </nav>
          <div className="sidebar-logout">
            <a href="/login" className="sidebar-link">Logout</a>
          </div>
        </aside>

        <main className="main-content">
          <h1>Booking Calendar</h1>

          {/* Stats */}
          <div className="stats-row">
            <div className="stat-card">
              <h3>Today's Check-ins</h3>
              <p>{todayReservations.length}</p>
              <div className="stat-sub">Guests staying today</div>
            </div>
            <div className="stat-card">
              <h3>Confirmed</h3>
              <p>{confirmedCount}</p>
              <div className="stat-sub">Total confirmed bookings</div>
            </div>
            <div className="stat-card">
              <h3>Pending</h3>
              <p>{pendingCount}</p>
              <div className="stat-sub">Awaiting confirmation</div>
            </div>
            <div className="stat-card">
              <h3>Total</h3>
              <p>{reservations.length}</p>
              <div className="stat-sub">All reservations</div>
            </div>
          </div>

          {/* Calendar Header */}
          <div className="calendar-header">
            <div className="calendar-nav">
              <button onClick={prevMonth}>&lt; Prev</button>
              <span className="calendar-title">{monthNames[currentMonth]} {currentYear}</span>
              <button onClick={nextMonth}>Next &gt;</button>
            </div>
            <button className="calendar-nav button btn-today" onClick={goToToday}>Today</button>
          </div>

          {/* Calendar */}
          {loading ? (
            <div className="loading">Loading reservations...</div>
          ) : error ? (
            <div className="error">{error}</div>
          ) : (
            <div className="calendar-container">
              <div className="calendar-weekdays">
                {weekDays.map((day) => (
                  <th key={day}>{day}</th>
                ))}
              </div>
              <div className="calendar-grid">
                {calendarDays.map((item, index) => {
                  if (!item.day) {
                    return <div key={`empty-${index}`} className="calendar-day other-month"></div>;
                  }

                  const isToday = item.date === todayStr;
                  const dayReservations = getReservationsForDate(item.date);

                  return (
                    <div
                      key={item.date}
                      className={`calendar-day ${isToday ? "today" : ""}`}
                    >
                      <div className="day-number">{item.day}</div>
                      <div className="day-events">
                        {dayReservations.slice(0, 3).map((r) => (
                          <div
                            key={r.id}
                            className={`event-chip ${(r.status || "").toLowerCase()}`}
                            onClick={() => setSelectedReservation(r)}
                            title={`${r.name} - ${r.room_type}`}
                          >
                            {r.name}
                          </div>
                        ))}
                        {dayReservations.length > 3 && (
                          <div className="event-chip" style={{ background: "#333", color: "#aaa" }}>
                            +{dayReservations.length - 3} more
                          </div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </main>
      </div>

      {/* Reservation Details Modal */}
      {selectedReservation && (
        <div className="modal-backdrop" onClick={() => setSelectedReservation(null)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={() => setSelectedReservation(null)}>×</button>
            <h3>Booking #{selectedReservation.id}</h3>
            
            <div className="detail-row">
              <span className="detail-label">Customer</span>
              <span className="detail-value">{selectedReservation.name}</span>
            </div>
            <div className="detail-row">
              <span className="detail-label">Room</span>
              <span className="detail-value">{selectedReservation.room_type || "-"}</span>
            </div>
            <div className="detail-row">
              <span className="detail-label">Check-in</span>
              <span className="detail-value">{selectedReservation.check_in}</span>
            </div>
            <div className="detail-row">
              <span className="detail-label">Check-out</span>
              <span className="detail-value">{selectedReservation.check_out}</span>
            </div>
            <div className="detail-row">
              <span className="detail-label">Guests</span>
              <span className="detail-value">{selectedReservation.adults} Adults, {selectedReservation.children} Children</span>
            </div>
            <div className="detail-row">
              <span className="detail-label">Total Amount</span>
              <span className="detail-value">₹{Number(selectedReservation.total_amount || 0).toLocaleString()}</span>
            </div>
            <div className="detail-row">
              <span className="detail-label">Status</span>
              <span className="detail-value" style={{ 
                color: selectedReservation.status === "Confirmed" ? "#4caf50" : 
                       selectedReservation.status === "Cancelled" ? "#e53935" : "#e6c34d" 
              }}>
                {selectedReservation.status}
              </span>
            </div>
            <div className="detail-row">
              <span className="detail-label">Contact</span>
              <span className="detail-value">{selectedReservation.phone || "-"}</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
